<template>
  <div class="radio-page">
    <main class="workspace">
      <aside class="terminal-panel panel">
        <div class="panel-heading"><div><h2>无线对讲终端</h2></div></div>
        <div class="terminal-summary"><span>在线 <b class="green">{{ onlineCount }}</b></span><span>离线 <b class="red">{{ terminals.length - onlineCount }}</b></span><span>设备数 <b class="blue">{{ terminals.length }}</b></span></div>
        <div class="search-row"><el-input v-model="keyword" clearable size="small" placeholder="搜索姓名或终端 ID" :prefix-icon="Search" /></div>
        <div class="terminal-list">
          <div v-for="terminal in filteredTerminals" :key="terminal.id" class="terminal-item" :class="{ selected: terminal.selected, offline: terminal.status === 'offline' }">
            <el-checkbox v-model="terminal.selected" :disabled="terminal.status === 'offline'" />
            <span class="status-dot" :class="terminal.status" />
            <div class="terminal-main" @click="activeTerminal = terminal"><strong>{{ terminal.name }}</strong><small>PDT-ID: {{ terminal.id }}</small></div>
            <div v-if="terminal.status === 'online'" class="quick-actions">
              <el-button circle text :icon="Phone" title="语音呼叫" @click="openAction('call', terminal)" />
              <el-button circle text :icon="VideoCamera" title="视频调阅" @click="openAction('video', terminal)" />
              <el-button circle text :icon="ChatDotRound" title="发送消息" @click="openAction('message', terminal)" />
            </div>
            <span v-else class="offline-label">离线</span>
          </div>
        </div>
        <div class="terminal-footer"><el-button type="primary" :disabled="selectedTerminals.length < 2" @click="groupDialog = true">+ 创建群组</el-button><span>至少选择 2 台在线终端</span></div>
      </aside>

      <section class="map-panel panel">
        <div class="map-toolbar"><el-radio-group v-model="mapFilter" size="small"><el-radio-button value="all">全部</el-radio-button><el-radio-button value="online">在线</el-radio-button><el-radio-button value="offline">离线</el-radio-button></el-radio-group></div>
        <div class="map-canvas">
          <img :src="mapImage" alt="园区地图" />
          <div class="map-wash" />
          <div v-for="terminal in visibleTerminals" :key="terminal.id" class="map-marker" :class="[terminal.status, { active: activeTerminal?.id === terminal.id }]" :style="{ left: `${terminal.left}%`, top: `${terminal.top}%` }" @click="activeTerminal = terminal">
            <span class="pulse" /><span class="marker-body"><el-icon><Microphone /></el-icon></span><b>{{ terminal.name }}</b>
            <div v-if="activeTerminal?.id === terminal.id" class="map-card" @click.stop>
              <div class="card-top"><span class="status-dot" :class="terminal.status" /><strong>{{ terminal.name }} <small>{{ terminal.id }}</small></strong><el-button text :icon="Close" @click="activeTerminal = null" /></div>
              <div class="card-state">当前状态 <b :class="terminal.status">{{ terminal.status === 'online' ? '在线' : '离线' }}</b></div>
              <div v-if="terminal.status === 'online'" class="card-actions"><el-button size="small" :icon="Phone" @click="openAction('call', terminal)">语音</el-button><el-button size="small" :icon="VideoCamera" @click="openAction('video', terminal)">视频</el-button><el-button size="small" :icon="ChatDotRound" @click="openAction('message', terminal)">消息</el-button></div>
              <div v-else class="offline-notice">设备离线，仅支持查看设备状态</div>
            </div>
          </div>
          <div class="map-legend"><span><i class="online" />在线 {{ onlineCount }}</span><span><i class="offline" />离线 {{ terminals.length - onlineCount }}</span></div>
          <div class="north">N</div>
        </div>

        <aside class="group-float" :class="{ collapsed: groupCollapsed }">
          <div class="group-head"><div><h2>对讲群组 <small>{{ groups.length }} 个群组</small></h2></div><el-button circle size="small" :icon="groupCollapsed ? ArrowLeft : ArrowRight" @click="groupCollapsed = !groupCollapsed" /></div>
          <template v-if="!groupCollapsed"><div v-for="group in groups" :key="group.id" class="group-item"><div class="group-icon"><el-icon><UserFilled /></el-icon></div><div class="group-detail"><strong>{{ group.name }}</strong><small>ID: {{ group.id }} · {{ group.members.length }} 台设备</small><div class="group-buttons"><el-button text size="small" :icon="Phone" @click="openGroupAction('call', group)">组呼</el-button><el-button text size="small" :icon="ChatDotRound" @click="openGroupAction('message', group)">群消息</el-button><el-button text size="small" @click="editGroup(group)">编辑</el-button><el-button text type="danger" size="small" @click="dissolveGroup(group)">解散</el-button></div></div></div></template>
        </aside>
      </section>
    </main>

    <el-dialog v-model="actionDialog" :title="actionTitle" width="430px" class="action-dialog" destroy-on-close>
      <div v-if="actionType === 'call'" class="call-content"><div class="avatar-circle"><el-icon><Phone /></el-icon></div><h2>{{ actionTerminal?.name }} <small>{{ actionTerminal?.id }}</small></h2><p class="call-status"><span class="live-dot" />{{ callConnected ? '已接通 · 00:12' : '呼叫中...' }}</p><el-button type="danger" round size="large" :icon="Phone" @click="actionDialog = false">挂断</el-button></div>
      <div v-else-if="actionType === 'video'" class="video-content"><div class="video-screen"><el-icon><VideoCamera /></el-icon><span>正在连接实时画面...</span></div><div class="video-device-label">{{ actionTerminal?.name }} <small>{{ actionTerminal?.id }}</small></div><el-button type="danger" round :icon="Phone" @click="actionDialog = false">挂断</el-button></div>
      <div v-else class="message-content"><div class="recipient"><span>收信人</span><b>{{ actionTerminal?.name }} {{ actionTerminal?.id }}</b></div><el-input v-model="messageText" type="textarea" :rows="7" maxlength="1500" show-word-limit placeholder="请输入要发送的消息" /><div class="dialog-actions"><el-button @click="actionDialog = false">取消</el-button><el-button type="primary" @click="sendMessage">发送</el-button></div></div>
    </el-dialog>

    <el-dialog v-model="groupActionDialog" :title="groupActionType === 'call' ? '组呼' : '群消息'" width="450px" destroy-on-close>
      <div v-if="groupActionType === 'call'" class="group-call"><div class="group-call-title"><div class="group-icon large"><el-icon><UserFilled /></el-icon></div><h2>{{ actionGroup?.name }}<small>组呼设备 · {{ actionGroup?.members.length }} 台</small></h2></div><div class="member-chips"><span v-for="member in actionGroup?.members" :key="member">{{ member }}</span></div><p class="call-status"><span class="live-dot" />组呼中...</p><el-button type="danger" round size="large" :icon="Phone" @click="groupActionDialog = false">挂断</el-button></div>
      <div v-else class="message-content"><div class="recipient"><span>发送至</span><b>{{ actionGroup?.name }}（{{ actionGroup?.members.length }} 台）</b></div><el-input v-model="messageText" type="textarea" :rows="7" maxlength="1500" show-word-limit placeholder="请输入群消息" /><div class="dialog-actions"><el-button @click="groupActionDialog = false">取消</el-button><el-button type="primary" @click="sendGroupMessage">发送</el-button></div></div>
    </el-dialog>

    <el-dialog v-model="editDialog" :title="`编辑群组成员 · ${editingGroup?.name || ''}`" width="720px">
      <div class="transfer-editor">
        <div class="transfer-column"><div class="transfer-title">未选择终端 <span>{{ availableTerminals.length }} 台</span></div><el-input v-model="transferKeyword" size="small" clearable placeholder="查找终端" :prefix-icon="Search" /><div class="transfer-list"><button v-for="terminal in availableTerminals" :key="terminal.id" class="transfer-item" @click="addMember(terminal)"><span class="status-dot" :class="terminal.status" /><span>{{ terminal.name }}</span><small>{{ terminal.id }}</small><b>+</b></button><div v-if="availableTerminals.length === 0" class="transfer-empty">暂无可添加终端</div></div></div>
        <div class="transfer-actions"><el-icon><ArrowRight /></el-icon><el-icon><ArrowLeft /></el-icon></div>
        <div class="transfer-column"><div class="transfer-title">当前群组终端 <span>{{ transferMembers.length }} 台</span></div><div class="transfer-list transfer-list--selected"><button v-for="terminal in transferMembers" :key="terminal.id" class="transfer-item" @click="removeMember(terminal)"><span class="status-dot" :class="terminal.status" /><span>{{ terminal.name }}</span><small>{{ terminal.id }}</small><b>−</b></button><div v-if="transferMembers.length === 0" class="transfer-empty">请从左侧添加终端</div></div></div>
      </div>
      <template #footer><el-button @click="editDialog = false">取消</el-button><el-button type="primary" @click="saveGroupMembers">保存</el-button></template>
    </el-dialog>

    <el-dialog v-model="groupDialog" title="创建群组" width="420px"><el-form label-position="top"><el-form-item label="群组名称"><el-input v-model="groupName" placeholder="请输入群组名称" maxlength="20" show-word-limit /></el-form-item><el-form-item label="已选终端"><div class="selected-chips"><span v-for="terminal in selectedTerminals" :key="terminal.id">{{ terminal.name }}</span></div></el-form-item></el-form><template #footer><el-button @click="groupDialog = false">取消</el-button><el-button type="primary" :disabled="!groupName" @click="createGroup">创建群组</el-button></template></el-dialog>
  </div>
</template>

<script setup lang="ts">
import { computed, ref } from 'vue'
import { ArrowLeft, ArrowRight, ChatDotRound, Close, Microphone, Phone, Search, UserFilled, VideoCamera } from '@element-plus/icons-vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import mapImage from '@/map.png'

type Status = 'online' | 'offline'
type Terminal = { id: string; name: string; status: Status; area: string; signal: string; lastReport: string; left: number; top: number; selected: boolean }
type Group = { name: string; id: string; members: string[] }
const keyword = ref(''); const mapFilter = ref<'all' | Status>('all'); const activeTerminal = ref<Terminal | null>(null); const groupCollapsed = ref(false)
const actionDialog = ref(false); const actionType = ref<'call' | 'video' | 'message'>('call'); const actionTerminal = ref<Terminal | null>(null); const callConnected = ref(false); const messageText = ref('')
const editDialog = ref(false); const transferKeyword = ref(''); const transferMemberIds = ref<string[]>([]); const editingGroup = ref<Group | null>(null); const groupDialog = ref(false); const groupName = ref(''); const groupActionDialog = ref(false); const groupActionType = ref<'call' | 'message'>('call'); const actionGroup = ref<Group | null>(null)
const terminals = ref<Terminal[]>([
  { id: '80002', name: '张三', status: 'online', area: 'T1 航站楼 / 一层大厅', signal: '优 · -48 dBm', lastReport: '2026-04-09 15:51:43', left: 28, top: 45, selected: false },
  { id: '80003', name: '李四', status: 'online', area: 'T1 航站楼 / 安检区', signal: '优 · -51 dBm', lastReport: '2026-04-09 15:51:39', left: 47, top: 30, selected: false },
  { id: '80006', name: '王大', status: 'online', area: '货运中心 / 3 号库', signal: '良 · -62 dBm', lastReport: '2026-04-09 15:51:35', left: 65, top: 58, selected: false },
  { id: '80008', name: '赵敏', status: 'offline', area: 'T2 航站楼 / 北侧通道', signal: '-', lastReport: '2026-04-09 15:51:43', left: 55, top: 45, selected: false },
  { id: '80011', name: '陈强', status: 'online', area: '综合办公楼 / 消控室', signal: '优 · -45 dBm', lastReport: '2026-04-09 15:51:41', left: 37, top: 73, selected: false },
])
const groups = ref<Group[]>([{ name: '消防应急 1 组', id: '0112', members: ['张三（80002）', '李四（80003）', '王大（80006）'] }, { name: '夜间巡逻组', id: '0115', members: ['赵敏（80008）', '陈强（80011）'] }])
const onlineCount = computed(() => terminals.value.filter((item) => item.status === 'online').length); const selectedTerminals = computed(() => terminals.value.filter((item) => item.selected)); const filteredTerminals = computed(() => terminals.value.filter((item) => `${item.name}${item.id}`.includes(keyword.value)))
const visibleTerminals = computed(() => terminals.value.filter((item) => mapFilter.value === 'all' || item.status === mapFilter.value))
const transferMembers = computed(() => terminals.value.filter((item) => transferMemberIds.value.includes(item.id)))
const availableTerminals = computed(() => terminals.value.filter((item) => !transferMemberIds.value.includes(item.id) && `${item.name}${item.id}`.includes(transferKeyword.value)))
const actionTitle = computed(() => actionType.value === 'call' ? '语音呼叫' : actionType.value === 'video' ? '实时画面' : '发送消息')
function openAction(type: 'call' | 'video' | 'message', terminal: Terminal) { actionType.value = type; actionTerminal.value = terminal; callConnected.value = false; messageText.value = ''; actionDialog.value = true }
function openGroupAction(type: 'call' | 'message', group: Group) { groupActionType.value = type; actionGroup.value = group; messageText.value = ''; groupActionDialog.value = true }
function sendMessage() { actionDialog.value = false; ElMessage.success(`消息已发送至 ${actionTerminal.value?.name}`) }
function sendGroupMessage() { groupActionDialog.value = false; ElMessage.success(`群消息已发送至 ${actionGroup.value?.name}`) }
function editGroup(group: Group) { editingGroup.value = group; transferMemberIds.value = group.members.map((member) => member.match(/(\d+)）$/)?.[1] || '').filter(Boolean); transferKeyword.value = ''; editDialog.value = true }
function addMember(terminal: Terminal) { transferMemberIds.value = [...transferMemberIds.value, terminal.id] }
function removeMember(terminal: Terminal) { transferMemberIds.value = transferMemberIds.value.filter((id) => id !== terminal.id) }
function saveGroupMembers() { if (!editingGroup.value) return; editingGroup.value.members = transferMembers.value.map((terminal) => `${terminal.name}（${terminal.id}）`); editDialog.value = false; ElMessage.success('群组成员已更新') }
function createGroup() { groups.value.unshift({ name: groupName.value, id: `0${Math.floor(Math.random() * 900 + 100)}`, members: selectedTerminals.value.map((item) => `${item.name}（${item.id}）`) }); selectedTerminals.value.forEach((item) => { item.selected = false }); groupName.value = ''; groupDialog.value = false; ElMessage.success('群组创建成功') }
function dissolveGroup(group: Group) { ElMessageBox.confirm(`确定解散“${group.name}”吗？解散后群组成员关系将被清除。`, '解散群组确认', { type: 'warning', confirmButtonText: '确认解散', cancelButtonText: '取消' }).then(() => { groups.value = groups.value.filter((item) => item.id !== group.id); ElMessage.success('群组已解散') }).catch(() => undefined) }
</script>

